const items = [];
for (const it of $input.all()) {
  const c = it.json;
  const nome = c.campaign_name || '';
  let tipo = 'NAO_CLASSIFICADO';
  const u = nome.toUpperCase();
  if (u.includes('UBER') || u.includes('99') || u.includes('INDRIVE') || u.includes('MOBILIDADE')) tipo = 'APP_MOBILIDADE';
  else if (u.includes('NAV') || u.includes('SERV') || u.includes('PUB')) tipo = 'SERVIDOR_PUBLICO';
  const conversas = (c.actions || []).find(a => a.action_type === 'onsite_conversion.messaging_conversation_started_7d' || a.action_type === 'messaging_conversation_started_7d')?.value;
  const cprObj = (c.cost_per_action_type || []).find(a => a.action_type === 'onsite_conversion.messaging_conversation_started_7d' || a.action_type === 'messaging_conversation_started_7d');
  const impressoes = Number(c.impressions || 0);
  const cliques = Number(c.clicks || 0);
  items.push({ json: {
    campaign_id: c.campaign_id,
    nome,
    tipo,
    status: 'ACTIVE',
    impressoes,
    alcance: Number(c.reach || 0),
    cliques,
    resultados: Number(conversas || 0),
    gasto: Number(c.spend || 0),
    cpr: Number(cprObj?.value || 0),
    cpm: impressoes > 0 ? (Number(c.spend || 0) / impressoes) * 1000 : 0,
    ctr: impressoes > 0 ? cliques / impressoes : 0,
    raw_actions: JSON.stringify(c.actions || [])
  } });
}
return items;
